import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

const CATEGORIES = ['🛒 Покупки', '🚚 Переезд', '🔧 Ремонт', '🌿 Сад', '💻 IT помощь', '📷 Фото', '🎓 Обучение', '🐾 Животные'];

export default function Home() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [myTasks, setMyTasks] = useState([]);

  useEffect(() => {
    if (user) {
      api.get('/tasks/my').then(res => setMyTasks(res.data.slice(0, 3))).catch(() => {});
    }
  }, [user]);

  return (
    <div className="app-container">
      {/* Header */}
      <div style={{
        padding: '16px 20px',
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        background: 'white', borderBottom: '1px solid var(--border)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{
            width: 36, height: 36, background: 'var(--green)',
            borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center'
          }}>
            <span style={{ color: 'white', fontSize: 12, fontWeight: 800 }}>QK</span>
          </div>
          <span style={{ fontWeight: 800, fontSize: 18 }}>QolKomek</span>
        </div>
        {user ? (
          <Link to="/profile" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <div style={{
              width: 38, height: 38, borderRadius: '50%',
              background: 'var(--green-pale)', border: '2px solid var(--green)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 16, fontWeight: 700, color: 'var(--green)'
            }}>
              {user.username?.[0]?.toUpperCase()}
            </div>
          </Link>
        ) : (
          <Link to="/signin" className="btn-primary" style={{ width: 'auto', padding: '8px 16px', fontSize: 14 }}>
            Войти
          </Link>
        )}
      </div>

      <div style={{ padding: '20px 20px 100px' }}>
        {/* Hero */}
        <div style={{
          background: 'linear-gradient(135deg, var(--green) 0%, var(--green-light) 100%)',
          borderRadius: 20, padding: '24px 20px', marginBottom: 24,
          boxShadow: '0 8px 24px rgba(58,125,44,0.25)'
        }}>
          <p style={{ color: 'rgba(255,255,255,0.8)', fontSize: 14, marginBottom: 4 }}>
            {user ? `Привет, ${user.username}! 👋` : 'Добро пожаловать!'}
          </p>
          <h2 style={{ color: 'white', fontSize: 20, fontWeight: 800, marginBottom: 16, lineHeight: 1.3 }}>
            Найди надёжных помощников рядом
          </h2>
          <button
            onClick={() => navigate('/map')}
            style={{
              background: 'white', color: 'var(--green)', border: 'none',
              padding: '10px 20px', borderRadius: 10, fontWeight: 700, fontSize: 14
            }}
          >
            🗺️ Открыть карту
          </button>
        </div>

        {/* Action buttons */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 24 }}>
          <Link to="/map" style={{
            background: 'white', borderRadius: 14, padding: '16px',
            boxShadow: 'var(--shadow)', textAlign: 'center', display: 'block'
          }}>
            <div style={{ fontSize: 28, marginBottom: 6 }}>🔍</div>
            <div style={{ fontWeight: 700, fontSize: 14 }}>Найти задачу</div>
            <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>Стать героем</div>
          </Link>
          <Link to="/create-task" style={{
            background: 'var(--green)', borderRadius: 14, padding: '16px',
            boxShadow: '0 4px 16px rgba(58,125,44,0.3)', textAlign: 'center', display: 'block'
          }}>
            <div style={{ fontSize: 28, marginBottom: 6 }}>➕</div>
            <div style={{ fontWeight: 700, fontSize: 14, color: 'white' }}>Создать задачу</div>
            <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.7)', marginTop: 2 }}>Нужна помощь?</div>
          </Link>
        </div>

        {/* My Tasks */}
        {user && (
          <div style={{ marginBottom: 24 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
              <h3 style={{ fontWeight: 700, fontSize: 16 }}>Мои задачи</h3>
              <Link to="/my-tasks" style={{ color: 'var(--green)', fontSize: 13, fontWeight: 600 }}>Все →</Link>
            </div>
            {myTasks.length === 0 ? (
              <div style={{
                background: 'white', borderRadius: 14, padding: '20px',
                textAlign: 'center', color: 'var(--text-muted)',
                boxShadow: 'var(--shadow)', fontSize: 14
              }}>
                Вы ещё не создали задачи
              </div>
            ) : (
              myTasks.map(task => (
                <Link key={task.id} to={`/tasks/${task.id}`} style={{
                  display: 'block', background: 'white', borderRadius: 14, padding: '14px',
                  marginBottom: 8, boxShadow: 'var(--shadow)'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <span style={{ fontWeight: 600, fontSize: 15 }}>{task.title}</span>
                    <span className={`badge badge-${task.status}`}>{task.status}</span>
                  </div>
                  {task.category && (
                    <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 4 }}>{task.category}</div>
                  )}
                </Link>
              ))
            )}
          </div>
        )}

        {/* Categories */}
        <div style={{ marginBottom: 24 }}>
          <h3 style={{ fontWeight: 700, fontSize: 16, marginBottom: 12 }}>Популярные категории</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => navigate(`/map?category=${encodeURIComponent(cat)}`)}
                style={{
                  background: 'white', border: '1.5px solid var(--border)',
                  borderRadius: 12, padding: '10px 12px', fontSize: 13,
                  fontWeight: 600, textAlign: 'left', cursor: 'pointer',
                  transition: 'border-color 0.2s'
                }}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Bottom nav */}
      <BottomNav />
    </div>
  );
}

