            color: current === item.path ? 'var(--green)' : 'var(--text-muted)',
            fontWeight: current === item.path ? 700 : 500
          }}
        >
          <span style={{ fontSize: 20 }}>{item.icon}</span>
          <span style={{ fontSize: 10 }}>{item.label}</span>
        </button>
      ))}
    </div>
  );
}
